   225→function normalizeVisionResult(parsed) {
   226→  if (!parsed || typeof parsed !== 'object') return parsed;
   227→  const result = { ...parsed };
   228→
   229→  // Normalize field name variations
   230→  const fieldMappings = {
   231→    eye_contact: ['eye_contact', 'eyeContact', 'eye_contact_score', 'gaze'],
