   235→    overall_presentation: ['overall_presentation', 'overallPresentation', 'overall_score', 'overall'],
   236→  };
   237→
   238→  for (const [target, alternatives] of Object.entries(fieldMappings)) {
   239→    if (!result[target]) {
   240→      for (const alt of alternatives) {
   241→        if (result[alt] !== undefined) {
   242→          result[target] = result[alt];
   243→          break;
   244→        }
   245→      }
   246→    }
   247→    // Normalize score-only values into {score, feedback} objects
   248→    if (target !== 'overall_presentation' && result[target] !== undefined) {
