   588→async function transcribeAudioWithWhisper(audioBase64, options = {}) {
   589→  try {
   590→    // Strip full data URL prefix including codec params (e.g., data:audio/webm;codecs=opus;base64,)
   591→    const base64Data = audioBase64.replace(/^data:audio\/[^;]+(?:;[^;]*)*;base64,/, '');
   592→    const buffer = Buffer.from(base64Data, 'base64');
   593→
   594→    // Extract MIME type (e.g., audio/webm from data:audio/webm;codecs=opus;base64,)
   595→    const mimeMatch = audioBase64.match(/^data:(audio\/[^;]+)/);
   596→    const mimeType = mimeMatch ? mimeMatch[1] : 'audio/webm';
   597→    const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm';
   598→    console.log(`[whisper] Audio format: ${mimeType}, ext: ${ext}, buffer size: ${buffer.length} bytes`);
   599→
   600→    // Use provider service with automatic fallback (Whisper → Parakeet)
   601→    return await aiProvider.transcribeAudio(buffer, `recording.${ext}`, mimeType, {
   602→      subscriptionId: options.subscriptionId,
   603→      module: 'mock_interview', feature: 'transcription',
   604→    });
   605→  } catch (err) {
   606→    console.error('Whisper transcription error:', err.message || err);
   607→    return null;
   608→  }
