   749→// Analyze speech transcription for communication quality
   750→function analyzeSpeechPatterns(transcription, durationSeconds) {
   751→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   752→  const wordCount = words.length;
   753→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   754→
   755→  // Filler word detection
   756→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   757→  const fillerCounts = {};
   758→  let totalFillers = 0;
   759→  const lowerTranscription = transcription.toLowerCase();
   760→
   761→  for (const filler of fillerWords) {
   762→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   763→    const matches = lowerTranscription.match(regex);
   764→    if (matches && matches.length > 0) {
   765→      fillerCounts[filler] = matches.length;
   766→      totalFillers += matches.length;
   767→    }
   768→  }
   769→
   770→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   771→
   772→  // Pace analysis
   773→  let paceAssessment = 'good';
   774→  let paceFeedback = '';
   775→  if (wpm < 100) {
   776→    paceAssessment = 'too_slow';
   777→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   778→  } else if (wpm < 120) {
   779→    paceAssessment = 'slightly_slow';
   780→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   781→  } else if (wpm <= 160) {
   782→    paceAssessment = 'good';
   783→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   784→  } else if (wpm <= 180) {
   785→    paceAssessment = 'slightly_fast';
   786→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   787→  } else {
   788→    paceAssessment = 'too_fast';
   789→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   790→  }
   791→
   792→  // Sentence structure analysis
   793→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   794→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   795→
   796→  // Communication score (1-10)
   797→  let communicationScore = 7;
   798→  // Penalize for filler words
   799→  if (fillerRate > 5) communicationScore -= 2;
   800→  else if (fillerRate > 3) communicationScore -= 1;
   801→  // Penalize for bad pace
   802→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   803→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   804→  // Reward for good sentence structure
   805→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   806→  // Penalize for very short responses
   807→  if (wordCount < 50) communicationScore -= 2;
   808→  else if (wordCount < 100) communicationScore -= 1;
   809→  // Reward for substantial responses
   810→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   811→
   812→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   813→
   814→  return {
   815→    word_count: wordCount,
   816→    duration_seconds: durationSeconds,
   817→    words_per_minute: wpm,
   818→    filler_words: fillerCounts,
   819→    total_fillers: totalFillers,
   820→    filler_rate: Math.round(fillerRate * 10) / 10,
   821→    pace: {
   822→      assessment: paceAssessment,
   823→      wpm,
   824→      feedback: paceFeedback
   825→    },
   826→    sentence_count: sentences.length,
   827→    avg_sentence_length: avgSentenceLength,
   828→    communication_score: communicationScore,
   829→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   830→  };
   831→}
