   833→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   834→  const tips = [];
   835→
   836→  if (fillerRate > 3) {
   837→    const topFillers = Object.entries(fillerCounts)
   838→      .sort((a, b) => b[1] - a[1])
   839→      .slice(0, 3)
   840→      .map(([word, count]) => `"${word}" (${count}x)`);
   841→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   842→  }
   843→
   844→  if (wpm > 160) {
   845→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   846→  } else if (wpm < 110) {
   847→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   848→  }
   849→
   850→  if (wordCount < 80) {
   851→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   852→  }
   853→
   854→  if (tips.length === 0) {
   855→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   856→  }
   857→
   858→  return tips;
