   976→
   977→  // Step 2: Run all analyses in parallel with PER-PROMISE timeouts + MASTER timeout
   978→  // BUG FIX (Feb 15, 2026 — Task #32681): Promise.allSettled was hanging forever when provider
   979→  // API calls never settled (HTTP response streaming but never completing). With 4 parallel calls
   980→  // each racing 3 providers (12 concurrent API requests from #32666), some providers become
   981→  // unresponsive. Fix: (1) Lower per-promise timeout to 18s, (2) Add a 25s master timeout on
   982→  // Promise.allSettled that force-resolves with partial results if any promise hangs.
   983→  const PER_PROMISE_TIMEOUT_MS = 18000;
   984→  const MASTER_TIMEOUT_MS = 25000;
   985→
   986→  function withTimeout(promise, ms, label) {
   987→    return new Promise((resolve, reject) => {
   988→      const timer = setTimeout(() => {
   989→        console.warn(`[video-analysis] ${label} timed out after ${ms}ms`);
   990→        reject(new Error(`${label} timeout after ${ms}ms`));
   991→      }, ms);
   992→      promise.then(
   993→        val => { clearTimeout(timer); resolve(val); },
   994→        err => { clearTimeout(timer); reject(err); }
   995→      );
   996→    });
   997→  }
   998→
   999→  // FIX (Feb 15, 2026): Pass transcription context to video presentation analysis
  1000→  // so the text-based LLM can generate personalized coaching from speech patterns
  1001→  const presentationOptions = {
  1002→    ...options,
  1003→    transcription: finalTranscription,
  1004→    durationSeconds,
  1005→    question,
  1006→  };
  1007→
  1008→  const analysisPromises = [
  1009→    withTimeout(analyzeInterviewResponse(question, finalTranscription, keyPoints, options), PER_PROMISE_TIMEOUT_MS, 'contentAnalysis'),
  1010→    withTimeout(generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options), PER_PROMISE_TIMEOUT_MS, 'contentCoaching'),
  1011→    withTimeout(analyzeVideoPresentation(frames, presentationOptions), PER_PROMISE_TIMEOUT_MS, 'videoPresentation'),
