  1013→    // analyzeVoiceQuality() only analyzes transcription TEXT (not audio) — gating it behind
  1014→    // audioData was wrong because it skipped voice analysis entirely when MediaRecorder failed
  1015→    // (common on iOS). This caused the Voice & Tone Analysis section to disappear from the UI.
  1016→    withTimeout(analyzeVoiceQuality(finalTranscription, durationSeconds, options), PER_PROMISE_TIMEOUT_MS, 'voiceAnalysis')
  1017→  ];
  1018→
  1019→  // FIX (Feb 15, 2026 — Task #32681): Track settlements individually so master timeout
  1020→  // can force-resolve with partial results instead of hanging forever.
  1021→  const partialResults = new Array(analysisPromises.length).fill(null);
  1022→  analysisPromises.forEach((p, i) => {
  1023→    p.then(
  1024→      val => { partialResults[i] = { status: 'fulfilled', value: val }; },
