  1315→// Generate session-end feedback for a mock interview
  1316→// Returns structured format matching practice interview: content + communication + presentation
  1317→async function generateSessionFeedback(conversation, targetRole, options = {}) {
  1318→  const convoText = conversation.map(turn => {
  1319→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1320→    return `CANDIDATE: ${turn.text}`;
  1321→  }).join('\n\n');
  1322→
  1323→  // Calculate basic metrics from the text
  1324→  const candidateTurns = conversation.filter(t => t.role === 'candidate');
  1325→  const allCandidateText = candidateTurns.map(t => t.text).join(' ');
  1326→  const wordCount = allCandidateText.split(/\s+/).filter(w => w).length;
  1327→  const questionCount = conversation.filter(t => t.role === 'interviewer').length;
  1328→
  1329→  // Estimate duration from timestamps
  1330→  let durationSeconds = 0;
  1331→  if (conversation.length >= 2) {
  1332→    const first = new Date(conversation[0].timestamp || Date.now());
  1333→    const last = new Date(conversation[conversation.length - 1].timestamp || Date.now());
  1334→    durationSeconds = Math.max(60, Math.round((last - first) / 1000));
  1335→  }
  1336→  const wpm = durationSeconds > 0 ? Math.round(wordCount / (durationSeconds / 60)) : 120;
  1337→
  1338→  const prompt = `You just completed a mock interview for a "${targetRole}" position. Review the full conversation and provide structured feedback in THREE sections matching our coaching format.
  1339→
  1340→FULL INTERVIEW TRANSCRIPT:
  1341→${convoText}
  1342→
  1343→SPEECH METRICS (from recording):
  1344→- Total words: ${wordCount}
  1345→- Questions answered: ${candidateTurns.length}
  1346→- Estimated duration: ${Math.round(durationSeconds / 60)} minutes
  1347→- Estimated WPM: ${wpm}
  1348→
  1349→Analyze the entire interview and return a JSON object with this EXACT structure:
  1350→
  1351→{
  1352→  "overall_score": 1-10,
  1353→  "interview_readiness": "ready|almost_ready|needs_work",
  1354→  "summary": "3-4 sentence overall assessment referencing specific answers",
  1355→
  1356→  "content": {
  1357→    "score": 1-10,
  1358→    "strengths": ["Specific strength with example from their answers — quote them", "Another strength"],
  1359→    "improvements": ["Specific improvement area with example", "Another improvement"],
  1360→    "covered_points": ["Key competency they demonstrated well"],
  1361→    "missed_points": ["Important area they didn't address or was weak"],
  1362→    "detailed_feedback": "2-3 paragraph deep analysis of their answer quality across ALL questions. Reference patterns: did they improve? Were some topics stronger? Did follow-ups reveal depth or gaps?",
  1363→    "specific_tips": ["Actionable tip 1", "Actionable tip 2", "Actionable tip 3"],
  1364→    "common_mistake": "The most common interview mistake they exhibited",
  1365→    "star_method_usage": { "score": 1-10, "feedback": "How well they structured answers with Situation-Task-Action-Result" },
  1366→    "technical_depth": { "score": 1-10, "feedback": "Depth of technical knowledge and specificity" }
  1367→  },
  1368→
  1369→  "communication": {
  1370→    "score": 1-10,
  1371→    "word_count": ${wordCount},
  1372→    "words_per_minute": ${wpm},
  1373→    "duration_seconds": ${durationSeconds},
  1374→    "filler_words": {"um": 0, "uh": 0, "like": 0, "you know": 0, "so": 0, "basically": 0},
  1375→    "total_fillers": 0,
  1376→    "filler_rate": 0.0,
  1377→    "pace": {
  1378→      "assessment": "good|slightly_fast|slightly_slow|too_fast|too_slow",
  1379→      "wpm": ${wpm},
  1380→      "feedback": "Assessment of their speaking pace and rhythm across the interview"
  1381→    },
  1382→    "tips": ["Speech improvement tip 1", "Tip 2"],
  1383→    "trends": "Did their communication improve/decline over the interview? More confident later? More filler words when nervous?"
  1384→  },
  1385→
  1386→  "question_scores": [
  1387→    { "question_summary": "Brief topic", "score": 1-10, "feedback": "1-2 sentences referencing their actual answer" }
  1388→  ],
  1389→
  1390→  "interview_arc": "How did the interview flow? Did the candidate warm up? Were they stronger on certain topic types? 2-3 sentences about the overall arc.",
  1391→  "top_tip": "Single most impactful thing to work on"
  1392→}
  1393→
  1394→IMPORTANT RULES:
  1395→- Be SPECIFIC. Quote their actual words. Reference real answers, not generic advice.
  1396→- For filler_words: estimate counts based on patterns you see in their text (hedge words, qualifiers like "I think", "kind of", "sort of", "you know", etc.)
  1397→- For communication.score: evaluate clarity, conciseness, structure, confidence across ALL answers
  1398→- For content.score: evaluate depth, specificity, relevance of their actual answer content
  1399→- Score honestly — 5 is average, 7 is good, only 8+ for genuinely impressive performance
  1400→- The "trends" field should note if they improved or worsened across the interview
  1401→- The "interview_arc" should describe the narrative of the full interview
  1402→
  1403→Only return the JSON object.`;
  1404→
  1405→  const result = await chat(prompt, {
  1406→    system: 'You are an expert career coach providing structured post-interview feedback. Analyze the ENTIRE interview conversation. Be specific — reference exact quotes and answers. Return valid JSON matching the exact schema requested.',
  1407→    maxTokens: 4096,
  1408→    subscriptionId: options.subscriptionId,
  1409→    module: 'mock_interview', feature: 'session_feedback'
  1410→  });
  1411→
  1412→  const parsed = safeParseJSON(result);
  1413→  if (parsed) {
  1414→    // Ensure backward compatibility — keep legacy fields for any UI that still reads them
  1415→    if (parsed.content) {
  1416→      parsed.strengths = parsed.strengths || parsed.content.strengths;
  1417→      parsed.improvements = parsed.improvements || parsed.content.improvements;
  1418→      if (parsed.content.star_method_usage) parsed.star_method_usage = parsed.content.star_method_usage;
  1419→      if (parsed.content.technical_depth) parsed.technical_depth = parsed.content.technical_depth;
  1420→      if (!parsed.communication_quality && parsed.communication) {
  1421→        parsed.communication_quality = { score: parsed.communication.score, feedback: parsed.communication.trends || '' };
  1422→      }
  1423→      if (!parsed.confidence_score && parsed.communication) {
  1424→        parsed.confidence_score = { score: parsed.communication.score, feedback: 'See communication analysis for details.' };
  1425→      }
  1426→    }
  1427→    return parsed;
  1428→  }
  1429→  // BUG FIX #4: Improved fallback with conversation-based analysis instead of "Detailed feedback unavailable"
  1430→  console.warn('[session-feedback] Failed to parse LLM response, computing basic feedback from conversation');
  1431→  const avgResponseLength = candidateTurns.length > 0
  1432→    ? Math.round(allCandidateText.split(/\s+/).length / candidateTurns.length)
  1433→    : 0;
  1434→  const depthScore = avgResponseLength > 100 ? 7 : avgResponseLength > 50 ? 5 : 3;
  1435→  const basicScore = Math.min(8, Math.max(3, Math.round((depthScore + (candidateTurns.length > 4 ? 2 : 0)) / 1.2)));
  1436→
  1437→  return {
  1438→    overall_score: basicScore,
  1439→    interview_readiness: basicScore >= 6 ? 'almost_ready' : 'needs_work',
  1440→    summary: `You completed a ${targetRole} mock interview answering ${candidateTurns.length} question(s) with an average of ${avgResponseLength} words per answer. ${avgResponseLength > 80 ? 'Your responses showed good detail.' : 'Try to expand your answers with more specific examples.'} AI-powered detailed analysis was temporarily unavailable — try another interview for full feedback.`,
  1441→    strengths: candidateTurns.length >= 3
  1442→      ? ['Completed multiple questions — consistency matters', 'Showed willingness to engage with the interviewer']
  1443→      : ['Started the interview process — practice builds confidence'],
  1444→    improvements: avgResponseLength < 60
  1445→      ? ['Expand your answers with specific examples and metrics', 'Use the STAR method: Situation, Task, Action, Result']
  1446→      : ['Try to include quantifiable results in your answers', 'Practice structuring answers with clear beginning, middle, and end'],
  1447→    question_scores: [],
  1448→    content: { score: depthScore, strengths: [], improvements: [], covered_points: [], missed_points: [], detailed_feedback: '', specific_tips: [], common_mistake: '', star_method_usage: { score: depthScore, feedback: 'Detailed STAR analysis unavailable' }, technical_depth: { score: depthScore, feedback: 'Detailed technical analysis unavailable' } },
  1449→    communication: { score: depthScore, word_count: wordCount, words_per_minute: wpm, duration_seconds: durationSeconds, filler_words: {}, total_fillers: 0, filler_rate: 0, pace: { assessment: 'average', wpm, feedback: '' }, tips: [] },
  1450→    star_method_usage: { score: depthScore, feedback: 'Detailed STAR analysis unavailable' },
  1451→    communication_quality: { score: depthScore, feedback: '' },
  1452→    technical_depth: { score: depthScore, feedback: '' },
  1453→    top_tip: 'The best interview tip: practice regularly. Each session makes you more confident.'
  1454→  };
  1455→}
