  1457→// ─── TTS: Now with automatic fallback + database caching ─────
  1458→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1459→async function textToSpeech(text, options = {}) {
  1460→  const pool = require('./db');
  1461→  const crypto = require('crypto');
  1462→
  1463→  try {
  1464→    const voice = options.voice || 'nova';
  1465→    const speed = options.speed || 1.0;
  1466→
  1467→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1468→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1469→
  1470→    // Generate cache key from text + voice
  1471→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1472→
  1473→    // Check cache first — serves audio even when daily token limit is exhausted
  1474→    try {
  1475→      const cached = await pool.query(
  1476→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1477→        [cacheKey]
  1478→      );
  1479→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1480→        const buf = Buffer.from(cached.rows[0].audio_data);
  1481→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1482→        return buf;
  1483→      }
  1484→    } catch (cacheErr) {
  1485→      // Cache miss or table doesn't exist yet — continue to API
  1486→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1487→    }
  1488→
  1489→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1490→
  1491→    // Use provider service with automatic fallback
  1492→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1493→      voice,
  1494→      speed,
  1495→      subscriptionId: options.subscriptionId,
  1496→      module: 'mock_interview', feature: 'tts',
  1497→    });
  1498→
  1499→    if (!buf) {
  1500→      console.log('[tts] All providers failed, returning null for browser fallback');
  1501→      return null;
  1502→    }
  1503→
  1504→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1505→
  1506→    // Cache the audio for future use (non-blocking)
  1507→    if (buf.length > 100) {
  1508→      pool.query(
  1509→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1510→         VALUES ($1, $2, $3, $4)
  1511→         ON CONFLICT (text_hash) DO NOTHING`,
  1512→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1513→      ).then(() => {
  1514→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1515→      }).catch(err => {
  1516→        // Non-fatal — caching failure doesn't break TTS
  1517→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1518→      });
  1519→    }
  1520→
  1521→    return buf;
  1522→  } catch (err) {
  1523→    console.error('[tts] Error:', err.message || err);
  1524→    return null;
  1525→  }
  1526→}
