  1528→/**
  1529→ * Helper for route handlers to return clear errors when AI providers fail.
  1530→ * Returns 503 (retryable) for provider cascade failures, 500 for other errors.
  1531→ */
  1532→function handleAIError(res, err, featureName = 'AI feature') {
  1533→  if (err.allProvidersFailed) {
  1534→    return res.status(503).json({
  1535→      error: `${featureName} temporarily unavailable`,
  1536→      message: 'AI providers are experiencing issues. Please try again in a moment.',
  1537→      retryable: true,
  1538→      retryAfterMs: 5000,
  1539→      totalElapsedMs: err.totalElapsedMs || 0,
  1540→    });
  1541→  }
  1542→  console.error(`[${featureName}] Error:`, err.message || err);
  1543→  return res.status(500).json({ error: `Failed: ${featureName}` });
  1544→}
